class Solution:
    def splitArray(self, nums):
        def is_prime(x):
            if x < 2:
                return False
            d = 2
            while d * d <= x:
                if x % d == 0:
                    return False
                d += 1
            return True
        a = b = 0
        for i, v in enumerate(nums):
            if is_prime(i):
                a += v
            else:
                b += v
        return abs(a - b)

