class Solution:
    def splitArray(self, nums):
        n = len(nums)
        sieve = [True] * max(n, 2)
        sieve[0] = sieve[1] = False
        i = 2
        while i * i < n:
            if sieve[i]:
                for j in range(i * i, n, i):
                    sieve[j] = False
            i += 1
        a = b = 0
        for idx, v in enumerate(nums):
            if sieve[idx]:
                a += v
            else:
                b += v
        return abs(a - b)

