var splitArray = function(nums) {
    const n = nums.length;
    const m = Math.max(n, 2);
    const sieve = new Array(m).fill(true);
    sieve[0] = false; sieve[1] = false;
    for (let i = 2; i * i < n; i++) {
        if (sieve[i]) {
            for (let j = i * i; j < n; j += i) sieve[j] = false;
        }
    }
    let a = 0n, b = 0n;
    for (let idx = 0; idx < n; idx++) {
        if (sieve[idx]) a += BigInt(nums[idx]);
        else b += BigInt(nums[idx]);
    }
    let d = a - b;
    if (d < 0n) d = -d;
    return Number(d);
};
